    tags: ["ai", "captions", "instagram", "tools"], author: "Maya Chen",
    publishedAt: "2026-04-25", readingTime: 12, featured: false, trending: false, status: "published",
    metaTitle: "I Tested 7 AI Caption Writers for Instagram. Only 2 Are Worth It.",
